const b = $json.body || $json || {};
const tz = "America/Toronto";
const stamp = new Intl.DateTimeFormat("en-CA", { timeZone: tz, year: "numeric", month: "2-digit", day: "2-digit", hour: "2-digit", minute: "2-digit", hour12: false }).format(new Date());
const pick = (...ks) => { for (const k of ks) { if (b[k]) return String(b[k]).slice(0, 500); } return ""; };
const name = pick("name", "fullName", "full_name");
const phone = pick("phone", "tel", "phoneNumber");
const email = pick("email");
const charge = pick("charge", "ticketType", "ticket_type", "offence", "subject");
const message = pick("message", "details", "whatHappened", "what_happened");
const page = pick("page", "source", "path", "referer");
const gclid = pick("gclid");
const esc = (s) => String(s || "").replace(/&/g, "&amp;").replace(/</g, "&lt;");
const telHref = "tel:" + phone.replace(/[^0-9+]/g, "");
const subject = "New lead from blottman.ca: " + (name || "unknown") + (charge ? " (" + charge + ")" : "");
let html = "<div style=\"font-family:Arial,sans-serif;max-width:520px;margin:0 auto;color:#1F2937\">";
html += "<table cellspacing=\"0\" cellpadding=\"0\" style=\"width:100%;background:#0D1B2A\"><tr><td style=\"padding:12px 16px\"><span style=\"color:#C9A84C;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;letter-spacing:4px\">STENTH</span></td><td align=\"right\" style=\"padding:12px 16px\"><span style=\"color:#ffffff;font-family:Arial,sans-serif;font-size:12px;letter-spacing:1px\">Lead Alert</span></td></tr></table>";
html += "<h2 style=\"margin:18px 0 2px;color:#0D1B2A\">You have a new lead</h2>";
html += "<p style=\"margin:0 0 12px;color:#6B7280;font-size:13px\">Received " + stamp + ", Toronto time, via the blottman.ca contact form.</p>";
html += "<table cellspacing=\"0\" style=\"width:100%;font-size:14px;border-collapse:collapse\">";
const row = (k, v) => v ? "<tr><td style=\"padding:8px 10px;background:#F5F7FA;font-weight:bold;width:110px;vertical-align:top\">" + k + "</td><td style=\"padding:8px 10px;border-bottom:1px solid #e8e8e8\">" + v + "</td></tr>" : "";
html += row("Name", esc(name));
html += row("Phone", "<a href=\"" + telHref + "\" style=\"color:#0D1B2A;font-weight:bold;font-size:16px;text-decoration:none\">" + esc(phone) + "</a>");
html += row("Email", esc(email));
html += row("Charge", esc(charge));
html += row("Message", esc(message));
html += row("Page", esc(page));
html += "</table>";
html += "<p style=\"background:#FEF2F2;border-left:4px solid #B42318;padding:12px 14px;font-size:13px;line-height:1.6;margin-top:14px\"><b>Quick response wins cases.</b> A callback within five minutes makes this lead several times more likely to sign than one made an hour later.</p>";
html += "<p style=\"color:#6B7280;font-size:11px;border-top:1px solid #e8e8e8;padding-top:10px\">This lead has been saved to the Blottman Lead Tracker sheet. Update the Retained column once the outcome is known. Sent automatically by Stenth.</p></div>";
return [{ json: { Date: stamp, Name: name, Phone: phone, Email: email, Charge: charge, Message: message, Page: page, GCLID: gclid, Retained: "", Notes: "", subject: subject, html: html } }];
